2	import { describe, it, expect } from "vitest";
3	import { quote } from "./claim-office.js";
4	
5	describe("MHPCO Claim Office", () => {
6	  // Quote: empty and basic items
7	  it("quote with empty item list returns premium 5 (processing fee only)", () => {
8	    expect(quote({ yearsWithMHPCO: 0 }, [])).toBe(5);
9	  });
10	  it("quote with a single sword (plain, no modifiers) returns premium 115 (100 base + 10 first insurance + 5 fee)", () => {
11	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", material: "steel", enchantment: 0, cursed: false }])).toBe(115);
12	  });
13	  it("quote with a single amulet (plain, no modifiers) returns premium 71 (60 base + 6 first insurance + 5 fee)", () => {
14	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }])).toBe(71);
15	  });
16	  it("quote with a single staff (plain, no modifiers) returns premium 93 (80 base + 8 first insurance + 5 fee)", () => {
17	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "staff", material: "wood", enchantment: 0, cursed: false }])).toBe(93);
18	  });
19	  it("quote with a single potion (plain, no modifiers) returns premium 49 (40 base + 4 first insurance + 5 fee)", () => {
20	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "potion", material: "glass", enchantment: 0, cursed: false }])).toBe(49);
21	  });
22	
23	  // Quote: multiple items
24	  it("quote with two plain items sums their base premiums (sword + amulet = 100 + 60 = 160 base, +16 first insurance, +5 fee = 181)", () => {
25	    expect(quote({ yearsWithMHPCO: 0 }, [
26	      { type: "sword", material: "steel", enchantment: 0, cursed: false },
27	      { type: "amulet", material: "silver", enchantment: 0, cursed: false }
28	    ])).toBe(181);
29	  });
30	
31	  // Components (runes/moonstones)
32	  it.todo("quote with 2 runes returns base premium 50 (2 × 25)");
33	  it.todo("quote with 3 runes applies block discount (60 base premium, not 75)");
34	  it.todo("quote with 4 runes returns 100 (block requires exactly 3, no block applies)");
35	  it.todo("quote with 7 runes returns 175 base premium (one block of 3 + 4 single = 60 + 100)");
36	  it.todo("quote with 2 runes + 1 moonstone returns 75 base premium (no block: different types)");
37	  it.todo("quote with 3 runes + 3 moonstones returns 120 base premium (two separate blocks)");
38	
39	  // Item-specific modifiers
40	  it.todo("quote with cursed sword adds 50% surcharge on item base premium (100 + 50 curse)");
41	  it.todo("quote with sword at enchantment 5 adds 30% surcharge on item base premium");
42	  it.todo("quote with sword at enchantment 4 does not add high-enchantment surcharge");
43	  it.todo("quote with cursed sword at enchantment 5 stacks both surcharges");
44	
45	  // Modifier scope on multi-item policies
46	  it.todo("quote with cursed sword + plain amulet applies curse only to sword's base premium (210 before policy modifiers and fee)");
47	
48	  // Policy-wide modifiers
49	  it.todo("quote with customer at exactly 2 years applies 20% loyalty discount on policy total");
50	  it.todo("quote with customer at less than 2 years does not apply loyalty discount");
51	  it.todo("quote first insurance adds 10% surcharge per item on the policy");
52	  it.todo("quote follow-up contract (after first quote in scenario) applies 15% discount on policy total");
53	
54	  // Rounding
55	  it.todo("premium calculation yielding 197.5 rounds up to 198");
56	
57	  // Integration examples from spec
58	  it.todo("newcomer with cursed sword (steel, enchantment 3, 0 years) returns premium 165");
59	  it.todo("long-standing customer's second contract: cursed sword (enchantment 7, 3 years, 2nd quote) returns premium 160");
60	
61	  // Quote: error cases
62	  it.todo("quote with unknown item type causes CLI to exit non-zero with error to stderr");
63	
64	  // Claim: basic payouts
65	  it.todo("claim on regular sword (steel, enchantment 3) with damage 500 returns payout 400 (full reimbursement minus 100 deductible)");
66	  it.todo("claim on rune (insurance value 250) with damage 200 returns payout 100 (full reimbursement minus 100 deductible)");
67	
68	  // Claim: enchantment threshold
69	  it.todo("claim on steel sword enchantment 9 with damage 1000 returns payout 400 (50% reimbursement, then 100 deductible)");
70	
71	  // Claim: dragon material
72	  it.todo("claim on dragon-material sword enchantment 5 with damage 800 returns payout 700 (full reimbursement, then 100 deductible)");
73	  it.todo("claim on dragon-material sword enchantment 9 with damage 1000 returns payout 400 (50% rule wins, then deductible)");
74	  it.todo("claim on dragon-material sword enchantment 8 with damage 1000 returns payout 400 (high-enchantment clause applies, then deductible)");
75	
76	  // Claim: deductible per damage event
77	  it.todo("claim with two damaged items (sword 500 + amulet 300) applies deductible per item: payout 600");
78	
79	  // Claim: multiple items of the same type
80	  it.todo("policy covering two swords has insurance sum 2000 and cap 4000");
81	  it.todo("claim with two sword damages on a two-sword policy treats each as separate damage with own deductible");
82	  it.todo("claim with more sword damages than swords insured causes CLI to exit non-zero");
83	
84	  // Claim: cap
85	  it.todo("policy with sword + amulet has insurance sum 1600 and cap 3200");
86	  it.todo("policy with sword + 3 runes has insurance sum 1750 (block discount affects premium only, not cap)");
87	  it.todo("cap is based on unmodified insurance value (cursed sword cap = 2000)");
88	  it.todo("first claim of 1500 on sword (cap 2000) returns payout 1400 with remainingCap 600");
89	  it.todo("second claim of 1500 with remainingCap 600 returns payout 600 with remainingCap 0");
90	
91	  // Claim: rounding
92	  it.todo("payout calculation yielding 350.5 rounds down to 350");
93	
94	  // Claim: error cases
95	  it.todo("claim referencing item not in policy causes CLI to exit non-zero with error to stderr");
96	  it.todo("claim with negative damage amount causes CLI to exit non-zero with error to stderr");
97	
98	  // CLI integration
99	  it.todo("CLI reads scenario JSON from stdin and writes results JSON to stdout in step order");
100	});
