3	type Customer = { yearsWithMHPCO: number; previousContracts?: number };
4	type Item = {
5	  type: "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone";
6	  material?: string;
7	  enchantment?: number;
8	  cursed?: boolean;
9	};
10	
11	const PROCESSING_FEE = 5;
12	const FIRST_INSURANCE_RATE = 0.1;
13	
14	const BASE_PREMIUMS: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	};
20	
21	export function quote(_customer: Customer, items: Item[]): number {
22	  const itemsBase = items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
23	  const firstInsurance = itemsBase * FIRST_INSURANCE_RATE;
24	  return itemsBase + firstInsurance + PROCESSING_FEE;
25	}
